pragma solidity ^0.8.19;

contract AgentRegistry {
    address private owner;
    mapping(string => string) private latestPieceCid;

    event CheckpointUpdated(string indexed agentId, string pieceCid);

    constructor() {
        owner = msg.sender;
    }

    function update(string calldata agentId, string calldata pieceCid) external {
        require(msg.sender == owner, "Not the owner");
        latestPieceCid[agentId] = pieceCid;
        emit CheckpointUpdated(agentId, pieceCid);
    }

    function lookup(string calldata agentId) external view returns (string memory) {
        return latestPieceCid[agentId];
    }
}
